import { useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import axios from "axios";

import { API } from "@/App";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

import { toast } from "sonner";

import { GraduationCap } from "lucide-react";

const JoinSchoolPage = () => {
  const navigate = useNavigate();

  const { inviteCode } = useParams();

  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    invite_code: inviteCode || "",

    full_name: "",

    role: "",

    email: "",

    password: "",

    admission_number: "",
  });

  const updateField = (field, value) => {
    setFormData((prev) => ({
      ...prev,
      [field]: value,
    }));
  };

  const requiresAdmissionNumber =
    formData.role === "parent" ||
    formData.role === "student";

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.invite_code) {
      toast.error("Invite code is required");
      return;
    }

    if (!formData.full_name) {
      toast.error("Full name is required");
      return;
    }

    if (!formData.role) {
      toast.error("Please select a role");
      return;
    }

    if (!formData.email) {
      toast.error("Email is required");
      return;
    }

    if (!formData.password) {
      toast.error("Password is required");
      return;
    }

    if (
      requiresAdmissionNumber &&
      !formData.admission_number
    ) {
      toast.error("Admission number is required");
      return;
    }

    setLoading(true);

    try {
      const response = await axios.post(
  `${API}/auth/join-school`,
  {
    invite_code: formData.invite_code.trim(),

    full_name: formData.full_name.trim(),

    role: formData.role,

    email: formData.email
      .trim()
      .toLowerCase(),

    password: formData.password,

    admission_number:
      formData.admission_number?.trim() || null,
  }
);

console.log(
  "Join school response:",
  response?.data
);

toast.success(
  response?.data?.message ||
    "Account submitted successfully. Awaiting school administrator approval."
);

navigate("/login");

} catch (error) {

  console.error(
    "Join school error:",
    error?.response?.data || error
  );

  if (error?.response?.status === 404) {
    toast.error(
      "Join school backend route is missing"
    );
  } else {
    toast.error(
      error?.response?.data?.detail ||
      error?.response?.data?.message ||
      error?.message ||
      "Failed to join school"
    );
  }

} finally {

  setLoading(false);

}
  };

  return (
    <div className="min-h-screen bg-[#0B1120] flex items-center justify-center p-6">
      <Card className="w-full max-w-lg bg-[#1A2332] border-[#1E3A4F]/40">
        <CardHeader className="text-center space-y-4">
          <div className="mx-auto w-16 h-16 bg-emerald-600 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-600/20">
            <GraduationCap className="w-10 h-10 text-white" />
          </div>

          <div>
            <CardTitle className="text-3xl font-bold text-white">
              Join School
            </CardTitle>

            <CardDescription className="text-slate-400 mt-2">
              Create your school account using an invite code
            </CardDescription>
          </div>
        </CardHeader>

        <CardContent>
          <form
            onSubmit={handleSubmit}
            className="space-y-6"
          >
            <div className="space-y-2">
              <Label>Invite Code</Label>

              <Input
                value={formData.invite_code}
                onChange={(e) =>
                  updateField(
                    "invite_code",
                    e.target.value
                  )
                }
                placeholder="Enter school invite code"
                required
              />
            </div>

            <div className="space-y-2">
              <Label>Full Name</Label>

              <Input
                value={formData.full_name}
                onChange={(e) =>
                  updateField(
                    "full_name",
                    e.target.value
                  )
                }
                placeholder="Enter your full name"
                required
              />
            </div>

            <div className="space-y-2">
              <Label>Role</Label>

              <Select
                value={formData.role}
                onValueChange={(value) =>
                  updateField("role", value)
                }
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select role" />
                </SelectTrigger>

                <SelectContent>
                  <SelectItem value="teacher">
                    Teacher
                  </SelectItem>

                  <SelectItem value="finance">
                    Finance
                  </SelectItem>

                  <SelectItem value="secretary">
                    Secretary
                  </SelectItem>

                  <SelectItem value="student">
                    Student
                  </SelectItem>

                  <SelectItem value="parent">
                    Parent
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Email</Label>

              <Input
                type="email"
                value={formData.email}
                onChange={(e) =>
                  updateField("email", e.target.value)
                }
                required
              />
            </div>

            <div className="space-y-2">
              <Label>Password</Label>

              <Input
                type="password"
                value={formData.password}
                onChange={(e) =>
                  updateField("password", e.target.value)
                }
                required
              />
            </div>

            {requiresAdmissionNumber && (
              <div className="space-y-2">
                <Label>Admission Number</Label>

                <Input
                  value={formData.admission_number}
                  onChange={(e) =>
                    updateField(
                      "admission_number",
                      e.target.value
                    )
                  }
                  placeholder="Enter admission number"
                  required
                />
              </div>
            )}

            <Button
              type="submit"
              className="w-full"
              disabled={loading}
            >
              {loading
                ? "Creating Account..."
                : "Join School"}
            </Button>
          </form>

          <div className="mt-6 text-center text-sm text-slate-500">
            After submitting your account request, your school administrator
            must approve your access before you can log in.
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default JoinSchoolPage;
